{
  "type": "QUIZ",
  "lessonText": "Test your understanding of key game development concepts.",
  "data": {
    "questions": [
      {
        "question": "What is the primary purpose of a game engine?",
        "options": ["To create graphics", "To manage game logic", "To provide sound effects", "To design levels"],
        "correctAnswer": 1,
        "explanation": "A game engine primarily manages game logic, providing the framework for game development."
      },
      {
        "question": "Which of the following is NOT a common game genre?",
        "options": ["RPG", "Shooter", "Puzzle", "Database"],
        "correctAnswer": 3,
        "explanation": "Database is not a recognized game genre, while RPG, Shooter, and Puzzle are."
      },
      {
        "question": "What does 'game mechanics' refer to?",
        "options": ["Visual effects", "Player interactions", "Sound design", "Game marketing"],
        "correctAnswer": 1,
        "explanation": "Game mechanics refer to the rules and systems that govern player interactions within a game."
      },
      {
        "question": "What is prototyping in game development?",
        "options": ["Creating final assets", "Testing gameplay ideas", "Marketing the game", "Publishing the game"],
        "correctAnswer": 1,
        "explanation": "Prototyping involves testing gameplay ideas before finalizing the game design."
      }
    ]
  }
}
